def flatten(nested_list):
    result = []
    for item in nested_list:
        if isinstance(item, list):
            result.extend(flatten(item))
        else:
            result.append(item)
    return result

# Example usage
nested = [1, [2, [3, 4]], 5, [[6], 7]]
print(flatten(nested))  # [1, 2, 3, 4, 5, 6, 7]
```

```python
def flatten_gen(nested_list):
    for item in nested_list:
        if isinstance(item, list):
            yield from flatten_gen(item)
        else:
            yield item

# Example usage
nested = [1, [2, [3, 4]], 5, [[6], 7]]
print(list(flatten_gen(nested)))  # [1, 2, 3, 4, 5, 6, 7]

# Memory-efficient: process items one at a time
for item in flatten_gen(nested):
    print(item)  # Processes one item at a time
